SELECT 
FROM user
WHERE 1=1

    AND status = #{queryDTO.status}


    AND username LIKE CONCAT('%', #{queryDTO.username}, '%')


    AND phone LIKE CONCAT('%', #{queryDTO.phone}, '%')


    AND nickname LIKE CONCAT('%', #{queryDTO.nickname}, '%')


    AND sex = #{queryDTO.sex}


    AND user_type = #{queryDTO.userType}


    AND role = #{queryDTO.role}


    AND wechat_id = #{queryDTO.wechatId}


    AND (user_type != 2 OR user_type IS NULL) AND id != -999

ORDER BY created_time DESC

